public static ArrayList<ArrayList> powerset(ArrayList arr) {
    if (!arr.isEmpty()) {
        Object first = arr.get(0);
        arr.remove(0);
        ArrayList rest = arr;
        ArrayList<ArrayList> rest_subsets = powerset(rest);
        ArrayList<ArrayList> output = new ArrayList<ArrayList>();
        ArrayList<Object> to_add = new ArrayList<Object>();
        to_add.add(first);
        output.add(to_add);
        for (ArrayList subset : rest_subsets) {
            ArrayList<Object> newSubset = new ArrayList<Object>(to_add);
            newSubset.addAll(subset);
            output.add(newSubset);
        }
        output.addAll(rest_subsets);
        return output;
    } else {
        ArrayList<ArrayList> empty_set = new ArrayList<ArrayList>();
        empty_set.add(new ArrayList());
        return empty_set;
    }
}

